module RefModule (
    input clk,
    input rst,
    input signal_in,
    output reg zero_cross
);

reg obf_signal_prev;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        obf_signal_prev <= 1'b0;
        zero_cross <= 1'b0;
    end else begin
        zero_cross <= (obf_signal_prev == 1'b0 && signal_in == 1'b1) || 
                      (obf_signal_prev == 1'b1 && signal_in == 1'b0);
        obf_signal_prev <= signal_in;
    end
end

endmodule
